var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흐으으으음…….","JPN":"ほおおおおお……","ENG":"Hmmmmm....","TWN":"呃嗯嗯嗯嗯…"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"조리개 너머로 보이는 깨끗한 바다, 필터로 느껴지는 소금기 머금은 바람…….","JPN":"レンズ越しに見えるきれいな海、フィルターで感じられる潮気を含んだ風……","ENG":"The blue sea viewed through the aperture, salty wind blowing through the filter...","TWN":"越過橫膈膜看到的清澈大海，藉由過濾器受到鹹鹹的海風……"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"궤도 사이에 알알이 끼는 모래알, 검게 도색된 보디를 뜨겁게 달구는 태양까지…….","JPN":"装甲に挟まる砂粒、黒く塗色されたボディーを熱く熱す太陽まで……","ENG":"Sand getting into the caterpillar, and the sun burning my black painted body...","TWN":"卡在軌道間的沙粒，還有把身體烤焦的烈日……"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이제야 좀 휴가다운 휴가를 보내는구만.","JPN":"やっとバカンスらしいバカンスになってきたな。","ENG":"Now this is what I call a vacation.","TWN":"這才是真正的放假嘛！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그렇지 않나, 베로니카 양?","JPN":"そう思わないか、ベロニカ？","ENG":"Don’t you agree, Veronica?","TWN":"你說對不對，貝洛妮卡？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"응? 왜 그런가, 베로니카 양. 안색이 좋지 않네만?","JPN":"うむ？　どうしたのかね、ベロニカ。顔色がよくないな。","ENG":"Hm? What’s wrong? You don’t look so well.","TWN":"嗯？怎麼啦？你的臉色不太好？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"메이드로서……  전 그저 주인님께 송구할 따름입니다.","JPN":"メイドとして……私はただご主人様に申し訳ない気持ちでいっぱいです。","ENG":"As your maid... I am sorry, Master.","TWN":"身為女僕……我對主人感到抱歉。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그건 무슨 또 소린가?","JPN":"どういうことかね？","ENG":"Why?","TWN":"那又是什麼意思?"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님께서 안락한 휴가를 보내지 못한 건 메이드장인 제 책임이 가장 크기 때문입니다.","JPN":"ご主人様が穏やかなバカンスを過ごせなかったのは、メイド長である私の責任が最も大きいためです。","ENG":"I’m the one who is responsible for you not having a nice and relaxing vacation.","TWN":"主人沒能悠閒地度過假期，身為女僕長的我要負最大的責任。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하하하, 누가 그러던가?","JPN":"ハハハ、誰がそんなことを。","ENG":"Hah hah, who told you that?","TWN":"哈哈哈，誰說的？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"내가 아는 한, 누구도 그렇게 생각하지 않을 걸세.","JPN":"私の知る限り、誰もそう思っていないはずさ。","ENG":"As far as I know, no one will blame you for this.","TWN":"完全不會有人這麼想吧？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"아니요. 이건 제 스스로의 마음가짐 문제입니다.","JPN":"いいえ。これは自分自身の心構えの問題です。","ENG":"No, it’s a matter of principle.","TWN":"不，這是我自己心態的問題。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"자리를 지키도록 허락해 주신 이상, 지금부터라도 최선을 다해 주인님 곁을 보필하겠습니다.","JPN":"お供することを許していただいた以上、今からでも最善を尽くしてご主人様をそばでお守りします。","ENG":"Since you let me stay by your side, I want to serve you as best as I can.","TWN":"既然允許我堅守崗位，那從現在開始我會盡全力輔佐主人。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하하. 그럴 필요 없네.","JPN":"ハハハ、その必要はない。","ENG":"Hah hah. That won’t be necessary.","TWN":"哈哈，不用啦。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"모처럼의 휴가이지 않은가. 그러니 베로니카 양도 자신만의 추억을 쌓는 건 어떤가?","JPN":"せっかくの休みじゃないか。だからベロニカもここで思い出を作るのはどうかね？","ENG":"It’s a vacation. Why don’t you go and have fun yourself?","TWN":"這麼難得休假，你也留下屬於自己的回憶吧？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"걱정해 주시는 마음은 알겠지만, 전 그럴 수 없습니다.","JPN":"心配してくださる気持ちはわかりますが、私はそうすることができません。","ENG":"I understand your concern, but I can’t do that.","TWN":"我明白主人的好意，但我不能那樣。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"혹시 모를 위험을 대비하여 최소한의 경호인력은 필요합니다.","JPN":"万が一の危険に備えて、最低限の警護人員は必要です。","ENG":"Someone has to keep you safe just in case.","TWN":"必須維持最基本的人力保護主人的安全。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};